     1→job "transflow-orw-apply" {
     2→  datacenters = ["dc1"]
     3→  type        = "batch"
     4→
     5→  group "orw" {
     6→    task "openrewrite-apply" {
     7→      driver = "docker"
     8→
     9→      config {
    10→        image = "ghcr.io/your-org/openrewrite-runner:jvm-6.17.0" # pin digest
    11→        command = "/usr/local/bin/openrewrite"
    12→        args = [
    13→          "--engine", "openrewrite",
    14→          "--recipe-class", "${RECIPE_CLASS}",
    15→          "--coords", "${RECIPE_COORDS}",
    16→          "--timeout", "${RECIPE_TIMEOUT}"
    17→        ]
    18→      }
    19→
    20→      env = {
    21→        OUTPUT_DIR  = "/workspace/out"
    22→      }
    23→
    24→      resources { cpu = 500, memory = 1024 }
    25→
    26→      volume_mount { volume = "context" destination = "/workspace/context" read_only = true }
    27→      volume_mount { volume = "out"     destination = "/workspace/out"     read_only = false }
    28→
    29→      kill_timeout = "5m"
    30→      timeout      = "30m"
    31→    }
    32→
    33→    volume "context" { type = "host" source = "transflow-context" }
    34→    volume "out"     { type = "host" source = "transflow-out" }
    35→  }
    36→}
    37→
    38→

